// Rotary Flight App - glossary.js
// Glossary popup, chips, flashcards

const Glossary = {
  terms: {},

  async load() {
    try {
      const response = await fetch('../../assets/data/glossary.json');
      const data = await response.json();
      this.terms = data;
    } catch (e) {
      // Fallback inline glossary for local file usage
      this.terms = {
        'rotary flight': { def: 'Flight using rotating blades or wings to create lift.', comp: 'A type of heavier-than-air flight where lift is generated by rotating airfoils.', example: 'A helicopter achieves rotary flight with its spinning main rotor.' },
        'fixed-wing': { def: 'Aircraft that use rigid wings and forward motion to create lift.', comp: 'Airplanes are fixed-wing aircraft; they cannot hover without special thrust systems.', example: 'An airliner is a fixed-wing aircraft.' },
        'rotor': { def: 'A set of rotating blades that generates lift on a rotary-wing aircraft.', comp: 'The complete assembly of blades, hub, and mast that produces lift.', example: 'The main rotor sits on top of the helicopter.' },
        'rotor blade': { def: 'A long, shaped wing that spins to create lift.', comp: 'Each individual airfoil attached to the rotor hub.', example: 'Helicopters usually have two to eight rotor blades.' },
        'lift': { def: 'The upward force created by air moving over a wing or rotor blade.', comp: 'One of the four forces of flight; opposes weight.', example: 'Faster spinning creates more lift.' },
        'drag': { def: 'Air resistance that opposes motion through the air.', comp: 'One of the four forces of flight; opposes thrust.', example: 'Streamlined shapes reduce drag.' },
        'thrust': { def: 'The force that moves an aircraft forward or upward.', comp: 'One of the four forces of flight; opposes drag.', example: 'A helicopter rotor provides both lift and thrust.' },
        'weight': { def: 'The downward pull of gravity on an aircraft.', comp: 'One of the four forces of flight; opposes lift.', example: 'To climb, lift must exceed weight.' },
        'torque': { def: 'A twisting force. In helicopters, spinning the rotor one way tends to spin the body the other way.', comp: 'Newton\'s third law reaction force requiring anti-torque systems.', example: 'The tail rotor counters main rotor torque.' },
        'anti-torque': { def: 'A system that prevents the helicopter body from spinning opposite to the rotor.', comp: 'Includes tail rotors, NOTAR, or coaxial counter-rotating rotors.', example: 'The tail rotor provides anti-torque force.' },
        'tail rotor': { def: 'A small rotor on the tail that pushes against torque.', comp: 'Produces sideways thrust to counter main rotor torque and controls yaw.', example: 'Increasing tail rotor thrust yaws the nose.' },
        'collective': { def: 'The control that changes all rotor blade angles together.', comp: 'Increases or decreases total lift equally on all blades.', example: 'Pulling up the collective makes the helicopter climb.' },
        'cyclic': { def: 'The control that tilts the rotor disk to move in a direction.', comp: 'Changes blade pitch selectively during rotation to tilt the rotor.', example: 'Pushing the cyclic forward tilts the rotor and moves the helicopter forward.' },
        'yaw': { def: 'Rotation around the vertical axis (nose left or right).', comp: 'Controlled by the tail rotor or anti-torque system.', example: 'Pressing the foot pedals changes yaw.' },
        'pitch': { def: 'Rotation around the side-to-side axis (nose up or down).', comp: 'In helicopters, controlled by the cyclic stick.', example: 'Pulling back on the cyclic pitches the nose up.' },
        'roll': { def: 'Rotation around the front-to-back axis (tilting side to side).', comp: 'In helicopters, controlled by the cyclic stick sideways.', example: 'Moving the cyclic left rolls the helicopter left.' },
        'VTOL': { def: 'Vertical Takeoff and Landing; ability to lift off without a runway.', comp: 'Key capability of helicopters and some tiltrotors.', example: 'A helicopter uses VTOL to take off from a rooftop.' },
        'hover': { def: 'Remaining in one place in the air.', comp: 'Requires lift to equal weight and control inputs to maintain position.', example: 'Rescue helicopters hover over accident scenes.' },
        'autorotation': { def: 'A safety descent where the rotor spins from upward airflow after engine failure.', comp: 'Unpowered rotor rotation used for emergency landing.', example: 'Pilots practice autorotation for engine-out emergencies.' },
        'autogyro': { def: 'An aircraft with an unpowered rotor that spins from airflow, plus a propeller for thrust.', comp: 'Not a helicopter; rotor is not powered for lift.', example: 'An autogyro needs forward speed to keep the rotor spinning.' },
        'tiltrotor': { def: 'An aircraft with rotors that can tilt between vertical and horizontal positions.', comp: 'Combines VTOL capability with airplane-like forward speed.', example: 'The V-22 Osprey is a tiltrotor aircraft.' },
        'coaxial rotor': { def: 'Two rotors mounted one above the other, spinning in opposite directions.', comp: 'Cancels torque without a tail rotor.', example: 'The Kamov Ka-50 uses coaxial rotors.' },
        'tandem rotor': { def: 'Two large rotors, one at the front and one at the rear.', comp: 'Cancels torque and provides heavy lift capability.', example: 'The CH-47 Chinook has tandem rotors.' },
        'airfoil': { def: 'A shaped surface designed to create lift from airflow.', comp: 'Includes wings and rotor blades with curved upper surfaces.', example: 'A rotor blade is a type of airfoil.' },
        'angle of attack': { def: 'The angle between the blade and the oncoming air.', comp: 'Affects lift and drag; too high causes stall.', example: 'Increasing angle of attack increases lift until stall.' }
      };
    }
  },

  init() {
    this.load().then(() => {
      this.bindChips();
      this.renderGlossaryPage();
    });
  },

  bindChips() {
    document.querySelectorAll('.glossary-chip').forEach(chip => {
      chip.addEventListener('click', (e) => {
        const term = e.currentTarget.dataset.term;
        this.showPopup(term);
      });
    });
  },

  showPopup(term) {
    const info = this.terms[term.toLowerCase()];
    if (!info) return;
    let overlay = document.getElementById('glossary-modal');
    if (!overlay) {
      overlay = document.createElement('div');
      overlay.id = 'glossary-modal';
      overlay.className = 'modal-overlay';
      document.body.appendChild(overlay);
    }
    overlay.innerHTML = `
      <div class="modal-content" role="dialog" aria-modal="true" aria-labelledby="gloss-title">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:var(--space-4)">
          <h3 id="gloss-title" style="margin:0;text-transform:capitalize">${term}</h3>
          <button class="btn btn-sm btn-secondary" onclick="Glossary.closePopup()" aria-label="Close">✕</button>
        </div>
        <p><strong>Definition:</strong> ${info.def}</p>
        <p><strong>Competition definition:</strong> ${info.comp}</p>
        <p><strong>Example:</strong> <em>${info.example}</em></p>
      </div>
    `;
    overlay.classList.add('open');
    overlay.addEventListener('click', (e) => {
      if (e.target === overlay) this.closePopup();
    });
  },

  closePopup() {
    const overlay = document.getElementById('glossary-modal');
    if (overlay) overlay.classList.remove('open');
  },

  renderGlossaryPage() {
    const container = document.getElementById('glossary-content');
    if (!container) return;
    const range = container.dataset.range; // e.g., 'a-f'
    const [start, end] = range.split('-');
    const filtered = Object.entries(this.terms).filter(([term]) => {
      const first = term[0];
      return first >= start && first <= end;
    });

    let html = '';
    filtered.forEach(([term, info]) => {
      html += `
        <div class="vocab-card" data-term="${term}">
          <div class="vocab-term">${term}</div>
          <div class="vocab-def">${info.def}</div>
          <div class="caption mt-2"><strong>Example:</strong> ${info.example}</div>
        </div>
      `;
    });
    container.innerHTML = html;
  },

  search(query) {
    query = query.toLowerCase();
    return Object.entries(this.terms).filter(([term, info]) => {
      return term.includes(query) || info.def.toLowerCase().includes(query);
    });
  }
};

document.addEventListener('DOMContentLoaded', () => Glossary.init());
